def get_province_data(prov_key: str):
    """Return (weather_dict, tariff_dict) for a province key like "Prov1"."""
    if prov_key not in WEATHER_DATA:
        raise KeyError(f"Unknown province: {prov_key}. Available: {list(WEATHER_DATA.keys())}")
    return WEATHER_DATA[prov_key], TARIFF_DATA[prov_key]


def list_provinces():
    """Return list of (key, name) tuples for all 31 provinces."""
    return [(k, v["name"]) for k, v in TARIFF_DATA.items()]
